import Link from "next/link";
import { modules } from "@/lib/course-data";

type ModuleSidebarProps = {
  currentWeek: string;
};

export function ModuleSidebar({ currentWeek }: ModuleSidebarProps) {
  return (
    <aside className="rounded-2xl border border-white/10 bg-slate-900 p-4">
      <h2 className="mb-4 text-sm font-semibold uppercase tracking-[0.2em] text-cyan-400">
        Modules
      </h2>

      <nav className="flex flex-col gap-2">
        {modules.map((module) => {
          const active = module.slug === currentWeek;

          return (
            <Link
              key={module.slug}
              href={`/modules/${module.slug}`}
              className={
                active
                  ? "rounded-xl border border-cyan-400/30 bg-cyan-500/10 px-3 py-3 text-sm text-white"
                  : "rounded-xl px-3 py-3 text-sm text-slate-300 transition hover:bg-slate-800 hover:text-white"
              }
            >
              <div className="font-medium">{module.title}</div>
              <div className="mt-1 text-xs text-slate-400">{module.description}</div>
            </Link>
          );
        })}
      </nav>
    </aside>
  );
}