import { notFound } from "next/navigation";
import { modules } from "@/lib/course-data";
import { ModuleSidebar } from "@/components/navigation/module-sidebar";

type PageProps = {
  params: Promise<{ week: string }>;
};

export default async function ModulePage({ params }: PageProps) {
  const { week } = await params;
  const moduleData = modules.find((item) => item.slug === week);

  if (!moduleData) {
    notFound();
  }

  return (
    <section className="mx-auto max-w-7xl px-4 py-10 sm:px-6 lg:px-8">
      <div className="grid gap-6 lg:grid-cols-[320px_1fr]">
        <div className="lg:sticky lg:top-24 lg:self-start">
          <ModuleSidebar currentWeek={week} />
        </div>

        <div className="space-y-6">
          <section className="rounded-3xl border border-white/10 bg-slate-900 p-8">
            <p className="text-sm uppercase tracking-[0.2em] text-cyan-400">Module</p>
            <h1 className="mt-2 text-3xl font-black text-white">{moduleData.title}</h1>
            <p className="mt-4 max-w-3xl text-slate-300">{moduleData.description}</p>
          </section>

          <section className="rounded-2xl border border-white/10 bg-slate-900 p-6">
            <h2 className="text-xl font-semibold text-white">Lessons</h2>
            <ul className="mt-4 space-y-3 text-slate-300">
              {moduleData.lessons.map((lesson, index) => (
                <li key={lesson} className="rounded-xl bg-slate-800/60 px-4 py-3">
                  <div className="text-xs uppercase tracking-[0.2em] text-cyan-400">
                    Lesson {index + 1}
                  </div>
                  <div className="mt-1">{lesson}</div>
                </li>
              ))}
            </ul>
          </section>
        </div>
      </div>
    </section>
  );
}